import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Layout from '../components/shared/Layout';
import { campaignAPI } from '../utils/api';
import { PlatformIcons, PLATFORMS, CAMPAIGN_OBJECTIVES, KPI_DEFINITIONS, formatKPI } from '../utils/platforms';

const MOCK_CAMPAIGN = {
  _id: '1', name: 'Q4 Brand Awareness Drive', objective: 'awareness',
  status: 'active', totalBudget: 12000, currency: 'USD',
  startDate: new Date(Date.now() - 25 * 86400000).toISOString(),
  endDate: new Date(Date.now() + 35 * 86400000).toISOString(),
  tags: ['q4', 'brand'],
  platforms: [
    { platform: 'meta', budget: 4000, budgetType: 'lifetime', status: 'active', objective: 'awareness', metrics: { amountSpent: 3200, impressions: 280000, cpm: 11.4, totalClicks: 8400, ctr: 3.0, cpc: 0.38, conversions: 320, totalReach: 190000, addToCart: 980 } },
    { platform: 'google', budget: 3500, budgetType: 'lifetime', status: 'active', objective: 'awareness', metrics: { amountSpent: 2800, impressions: 195000, cpm: 14.4, totalClicks: 10500, ctr: 5.4, cpc: 0.27, conversions: 280, totalReach: 145000, addToCart: 740 } },
    { platform: 'tiktok', budget: 2500, budgetType: 'lifetime', status: 'paused', objective: 'awareness', metrics: { amountSpent: 2100, impressions: 420000, cpm: 5.0, totalClicks: 8400, ctr: 2.0, cpc: 0.25, conversions: 190, totalReach: 310000, addToCart: 580 } },
    { platform: 'youtube', budget: 2000, budgetType: 'lifetime', status: 'active', objective: 'awareness', metrics: { amountSpent: 1600, impressions: 160000, cpm: 10.0, totalClicks: 3200, ctr: 2.0, cpc: 0.5, conversions: 120, totalReach: 130000, addToCart: 350 } }
  ]
};

export default function CampaignDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [campaign, setCampaign] = useState(null);
  const [loading, setLoading] = useState(true);
  const [editingBudget, setEditingBudget] = useState(null);
  const [budgetValue, setBudgetValue] = useState('');
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    campaignAPI.getById(id)
      .then(res => setCampaign(res.data))
      .catch(() => setCampaign(MOCK_CAMPAIGN))
      .finally(() => setLoading(false));
  }, [id]);

  const togglePlatformStatus = async (platformId, currentStatus) => {
    const newStatus = currentStatus === 'active' ? 'paused' : 'active';
    try {
      const res = await campaignAPI.updatePlatformStatus(id, platformId, { status: newStatus });
      setCampaign(res.data);
    } catch {
      setCampaign(prev => ({
        ...prev,
        platforms: prev.platforms.map(p => p.platform === platformId ? { ...p, status: newStatus } : p)
      }));
    }
  };

  const saveBudget = async (platformId) => {
    setSaving(true);
    try {
      const res = await campaignAPI.updatePlatformBudget(id, platformId, { budget: Number(budgetValue) });
      setCampaign(res.data);
    } catch {
      setCampaign(prev => ({
        ...prev,
        platforms: prev.platforms.map(p => p.platform === platformId ? { ...p, budget: Number(budgetValue) } : p)
      }));
    } finally {
      setEditingBudget(null);
      setSaving(false);
    }
  };

  if (loading) return <Layout><div style={{ color: '#8b7baa', padding: 40, textAlign: 'center' }}>Loading campaign...</div></Layout>;
  if (!campaign) return <Layout><div style={{ color: '#8b7baa', padding: 40, textAlign: 'center' }}>Campaign not found</div></Layout>;

  const obj = CAMPAIGN_OBJECTIVES.find(o => o.id === campaign.objective);
  const totalSpent = (campaign.platforms || []).reduce((s, p) => s + (p.metrics?.amountSpent || 0), 0);
  const totalImpressions = (campaign.platforms || []).reduce((s, p) => s + (p.metrics?.impressions || 0), 0);
  const totalClicks = (campaign.platforms || []).reduce((s, p) => s + (p.metrics?.totalClicks || 0), 0);
  const totalConversions = (campaign.platforms || []).reduce((s, p) => s + (p.metrics?.conversions || 0), 0);

  return (
    <Layout>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 28 }}>
        <div>
          <button
            onClick={() => navigate('/campaigns')}
            style={{ background: 'none', border: 'none', color: '#8b7baa', cursor: 'pointer', fontSize: 13, padding: '0 0 12px', display: 'flex', alignItems: 'center', gap: 6 }}
          >
            ← Back to Campaigns
          </button>
          <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
            <h1 style={{ fontFamily: 'Syne', fontSize: 26, fontWeight: 800, color: '#e8e0f5', margin: 0 }}>
              {campaign.name}
            </h1>
            <span className={`status-${campaign.status}`} style={{ padding: '4px 12px', borderRadius: 20, fontSize: 12, fontWeight: 700 }}>
              {campaign.status}
            </span>
          </div>
          <div style={{ display: 'flex', gap: 16, marginTop: 8 }}>
            <span style={{ fontSize: 13, color: '#8b7baa' }}>{obj?.icon} {obj?.label}</span>
            {campaign.startDate && (
              <span style={{ fontSize: 13, color: '#8b7baa' }}>
                📅 {new Date(campaign.startDate).toLocaleDateString()} – {campaign.endDate ? new Date(campaign.endDate).toLocaleDateString() : 'Ongoing'}
              </span>
            )}
            <span style={{ fontSize: 13, color: '#8b7baa' }}>💰 {campaign.currency} {campaign.totalBudget?.toLocaleString()}</span>
          </div>
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button className="btn-secondary" onClick={() => navigate(`/campaigns/${id}/edit`)}>
            ✏️ Edit Campaign
          </button>
        </div>
      </div>

      {/* Summary KPI row */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 14, marginBottom: 28 }}>
        {[
          { label: 'Amount Spent', value: formatKPI(totalSpent, 'currency'), sub: `of $${campaign.totalBudget?.toLocaleString()} budget`, icon: '💰', color: '#a855f7' },
          { label: 'Impressions', value: formatKPI(totalImpressions, 'number'), sub: `across ${campaign.platforms?.length} platforms`, icon: '👁️', color: '#3b82f6' },
          { label: 'Total Clicks', value: formatKPI(totalClicks, 'number'), sub: `CTR ${totalImpressions > 0 ? ((totalClicks / totalImpressions) * 100).toFixed(2) : 0}%`, icon: '🖱️', color: '#10b981' },
          { label: 'Conversions', value: formatKPI(totalConversions, 'number'), sub: `CPA $${totalConversions > 0 ? (totalSpent / totalConversions).toFixed(2) : '0'}`, icon: '🎯', color: '#f59e0b' }
        ].map(stat => (
          <div key={stat.label} className="glass-card" style={{ padding: '20px 22px' }}>
            <div style={{ fontSize: 22, marginBottom: 8 }}>{stat.icon}</div>
            <div style={{ fontSize: 24, fontWeight: 800, fontFamily: 'Syne', color: stat.color, marginBottom: 4 }}>{stat.value}</div>
            <div style={{ fontSize: 12, fontWeight: 600, color: '#e8e0f5', marginBottom: 2 }}>{stat.label}</div>
            <div style={{ fontSize: 11, color: '#6b7280' }}>{stat.sub}</div>
          </div>
        ))}
      </div>

      {/* Platform breakdown */}
      <div className="glass-card" style={{ padding: 24, marginBottom: 24 }}>
        <h3 style={{ fontFamily: 'Syne', fontSize: 18, fontWeight: 700, color: '#e8e0f5', margin: '0 0 20px' }}>
          Platform Breakdown
        </h3>

        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                {['Platform', 'Status', 'Budget', 'Spent', 'Impressions', 'Clicks', 'CTR', 'CPC', 'Conversions', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '8px 14px', textAlign: 'left', fontSize: 11, color: '#6b7280', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '1px solid rgba(139,92,246,0.1)', whiteSpace: 'nowrap' }}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {(campaign.platforms || []).map(p => {
                const pl = PLATFORMS.find(x => x.id === p.platform);
                const Icon = PlatformIcons[p.platform];
                const m = p.metrics || {};
                const isEditing = editingBudget === p.platform;

                return (
                  <tr key={p.platform} style={{ borderBottom: '1px solid rgba(139,92,246,0.06)' }}>
                    <td style={{ padding: '14px 14px' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 9 }}>
                        {Icon && <Icon size={20} />}
                        <span style={{ fontSize: 13, fontWeight: 700, color: '#e8e0f5' }}>{pl?.name}</span>
                      </div>
                    </td>
                    <td style={{ padding: '14px 14px' }}>
                      <span className={`status-${p.status}`} style={{ padding: '3px 10px', borderRadius: 20, fontSize: 11, fontWeight: 700 }}>
                        {p.status}
                      </span>
                    </td>
                    <td style={{ padding: '14px 14px' }}>
                      {isEditing ? (
                        <div style={{ display: 'flex', gap: 6, alignItems: 'center' }}>
                          <input
                            type="number"
                            value={budgetValue}
                            onChange={e => setBudgetValue(e.target.value)}
                            style={{ width: 80, padding: '4px 8px', borderRadius: 6, background: 'rgba(26,16,51,0.8)', border: '1px solid rgba(124,58,237,0.4)', color: '#e8e0f5', fontSize: 12 }}
                            autoFocus
                          />
                          <button onClick={() => saveBudget(p.platform)} disabled={saving}
                            style={{ padding: '4px 8px', borderRadius: 6, background: 'rgba(74,222,128,0.15)', border: '1px solid rgba(74,222,128,0.3)', color: '#4ade80', cursor: 'pointer', fontSize: 11 }}>
                            ✓
                          </button>
                          <button onClick={() => setEditingBudget(null)}
                            style={{ padding: '4px 8px', borderRadius: 6, background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.3)', color: '#ef4444', cursor: 'pointer', fontSize: 11 }}>
                            ✕
                          </button>
                        </div>
                      ) : (
                        <div style={{ display: 'flex', alignItems: 'center', gap: 6, cursor: 'pointer' }}
                          onClick={() => { setEditingBudget(p.platform); setBudgetValue(p.budget); }}>
                          <span style={{ fontSize: 13, fontWeight: 600, color: '#e8e0f5' }}>${p.budget?.toLocaleString()}</span>
                          <span style={{ fontSize: 10, color: '#7c3aed' }}>✏️</span>
                        </div>
                      )}
                    </td>
                    <td style={{ padding: '14px 14px', fontSize: 13, color: '#c084fc', fontWeight: 600 }}>{formatKPI(m.amountSpent, 'currency')}</td>
                    <td style={{ padding: '14px 14px', fontSize: 13, color: '#e8e0f5' }}>{formatKPI(m.impressions, 'number')}</td>
                    <td style={{ padding: '14px 14px', fontSize: 13, color: '#e8e0f5' }}>{formatKPI(m.totalClicks, 'number')}</td>
                    <td style={{ padding: '14px 14px', fontSize: 13, color: m.ctr > 3 ? '#4ade80' : m.ctr > 1.5 ? '#fbbf24' : '#ef4444' }}>{formatKPI(m.ctr, 'percent')}</td>
                    <td style={{ padding: '14px 14px', fontSize: 13, color: '#e8e0f5' }}>{formatKPI(m.cpc, 'currency')}</td>
                    <td style={{ padding: '14px 14px', fontSize: 13, color: '#e8e0f5' }}>{formatKPI(m.conversions, 'number')}</td>
                    <td style={{ padding: '14px 14px' }}>
                      <button
                        onClick={() => togglePlatformStatus(p.platform, p.status)}
                        style={{
                          padding: '5px 12px', borderRadius: 6, fontSize: 11, fontWeight: 700, cursor: 'pointer',
                          background: p.status === 'active' ? 'rgba(251,191,36,0.1)' : 'rgba(74,222,128,0.1)',
                          border: `1px solid ${p.status === 'active' ? 'rgba(251,191,36,0.3)' : 'rgba(74,222,128,0.3)'}`,
                          color: p.status === 'active' ? '#fbbf24' : '#4ade80'
                        }}
                      >
                        {p.status === 'active' ? '⏸ Pause' : '▶ Resume'}
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Per-platform detailed KPIs */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 16 }}>
        {(campaign.platforms || []).map(p => {
          const pl = PLATFORMS.find(x => x.id === p.platform);
          const Icon = PlatformIcons[p.platform];
          const m = p.metrics || {};
          const budgetUsedPct = p.budget > 0 ? Math.min(100, (m.amountSpent / p.budget) * 100) : 0;

          return (
            <div key={p.platform} className="glass-card" style={{ padding: 22 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                  {Icon && <Icon size={24} />}
                  <span style={{ fontFamily: 'Syne', fontWeight: 700, fontSize: 15, color: '#e8e0f5' }}>{pl?.name}</span>
                </div>
                <span className={`status-${p.status}`} style={{ padding: '2px 8px', borderRadius: 20, fontSize: 10, fontWeight: 700 }}>{p.status}</span>
              </div>

              {/* Budget bar */}
              <div style={{ marginBottom: 16 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, color: '#8b7baa', marginBottom: 6 }}>
                  <span>Budget used</span>
                  <span>{budgetUsedPct.toFixed(0)}% — ${m.amountSpent?.toFixed(0)} / ${p.budget?.toLocaleString()}</span>
                </div>
                <div style={{ height: 6, borderRadius: 3, background: 'rgba(139,92,246,0.1)' }}>
                  <div style={{
                    height: '100%', borderRadius: 3, transition: 'width 0.5s ease',
                    width: `${budgetUsedPct}%`,
                    background: budgetUsedPct > 90 ? '#ef4444' : budgetUsedPct > 70 ? '#fbbf24' : `linear-gradient(90deg, ${pl?.color || '#7c3aed'}, ${pl?.color || '#a855f7'}bb)`
                  }} />
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
                {[
                  { label: 'Impressions', value: formatKPI(m.impressions, 'number') },
                  { label: 'Clicks', value: formatKPI(m.totalClicks, 'number') },
                  { label: 'CTR', value: formatKPI(m.ctr, 'percent') },
                  { label: 'CPC', value: formatKPI(m.cpc, 'currency') },
                  { label: 'CPM', value: formatKPI(m.cpm, 'currency') },
                  { label: 'Conversions', value: formatKPI(m.conversions, 'number') }
                ].map(stat => (
                  <div key={stat.label} style={{ padding: '8px 10px', borderRadius: 8, background: 'rgba(26,16,51,0.5)' }}>
                    <div style={{ fontSize: 10, color: '#6b7280', fontWeight: 600, textTransform: 'uppercase', marginBottom: 3 }}>{stat.label}</div>
                    <div style={{ fontSize: 14, fontWeight: 700, color: '#e8e0f5' }}>{stat.value}</div>
                  </div>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </Layout>
  );
}
